function parseKind(txt) {
const kindClass = {"Doujinshi":"同人志","Manga":"漫画", "Artist CG":"画师CG","Game CG":"游戏CG","Non-H":"无H","Image Set":"图集","Western":"西方","Cosplay":"Cosplay", "Misc":"杂项","Asian Porn":"亚洲色情","Private":"私有"};
txt[2] = txt[2].replace('pages','页');
txt[0] = kindClass[txt[0]];
return txt}

function parseTag(txt) {
const { java, source, cache } = this;
let kk = cache.getFromMemory('tagMap');
if(kk==null){
	let l = source.getVariable();
	kk = java.readTxtFile(l);
	if(kk==''){
source.setVariable(java.downloadFile("https://fastly.jsdelivr.net/gh/Ehviewer-Overhauled/EhTagTranslation/tag-translations/tag-translations-zh-rCN.json"));
          l = source.getVariable();
          kk = java.readTxtFile(l)}
       cache.putMemory('tagMap',kk)}
let rows = {"female":"女性","male":"男性","mixed":"混合","language":"语言","other":"其他","group":"团队","artist":"艺术家","cosplayer":"Coser","parody":"原作","character":"角色","reclass":"重新分类","temp":"临时"};

  function e2s(tag) {
    let regex = new RegExp(`"${tag}": "([^"]+)"`);
    let ii = kk.match(regex);
    if (!ii) {return tag}return ii[1]}

  const lines = txt.split('\n');
  const obj = {};

  lines.forEach(line => {
    let [category, tag] = line.split(':');
    if (!obj[category]) {
      obj[category] = [];
    }
    obj[category].push(tag.replace(/_/g, ' '));
  });

  return Object.entries(obj)
    .map(([category, tags]) => {
      const row = rows[category] || category;
      const pTags = tags.map(tag => e2s(tag)+'('+tag+')').join(', ');
      return `${row}: ${pTags}`;
    })
    .join('\n');
}

