ruleToc.chapterList:
@js:
let baseUrlPattern = /h=(.+?)&/;
let bookIdPattern = /bookid=(\d+?)&/;
let matchPattern = /1-\\\/-(\d+)-\\\/-(.*?)(-\\\/(-vip|-unvip)?|")/g;

var SIGN_KEY = 'stvmobilereader&sajax=readchapter&erogh982^%*%^*';

var infoMap = source.getLoginHeaderMap()
let cookieHeader = 'transmode=chinese;' + (infoMap && infoMap!= null?(infoMap.cookie || ""):"");

let hMatch = baseUrl.match(baseUrlPattern);
let bookIdMatch = baseUrl.match(bookIdPattern);

if (!hMatch || !bookIdMatch) {
  throw new Error("没有获取到书籍信息");
}

let h = hMatch[1];
let bid = bookIdMatch[1];

let resultArray = [];

result.replace(matchPattern, (match, urlIndex, name,k ,vips) => {
  let sign = java.md5Encode(`bookid=${bid}&c=${urlIndex}&h=${h}&key=${SIGN_KEY}`);

  let headers = JSON.stringify({
    headers: {
      cookie: cookieHeader,
      'X-STV-Sign': sign
    }
  });
let url = `${getUrl()}/index.php?sajax=readchapter&h=${h}&bookid=${bid}&c=${urlIndex}&key=stvmobilereader,${headers}`;
  resultArray.push({
    name: String(vips+name).replace(/undefined/g, '').replace(/-unvip/g, '🔑').replace(/-vip/g, "🔒"),
   url:String(url),
   vips:String(vips)
  });
  return match;
});

resultArray;

