let statusMap = {
  null: "0️⃣",
  free: "🆓",
  vip: "3️⃣",
  marauder: "2️⃣",
  post: "1️⃣",
  BatteryFullIcon: "3️⃣",
  Battery5BarIcon: "2️⃣",
  Battery2BarIcon: "1️⃣",
  CheckCircleOutlineIcon: "🆓",
  MoneyIcon: "未解锁"
};
let payStatusMap = {
  HighlightOffIcon: "isClosed",
  CheckCircleOutlineIcon: "isFree",
  BatteryFullIcon: "isPay",
  Battery5BarIcon: "isPay",
  Battery2BarIcon: "isPay",
};

function getUserchap(item) {
  if (item.free == true) return statusMap.free;
  let userchap = item.userchap[0];
  if (userchap.modes == null) return statusMap.null;
  let modes = String(userchap.modes).replace(/\w+/g, (m) => statusMap[m]);
  return `${userchap.chapters}章 ${modes}`
}

function getUserchap1(item) {
  if (item == "") return statusMap.null;
  let modes = String(item).replace(/([\w\d]+)(?:(\n)|($))/g, (m, n1, n2, n3) => `${statusMap[n1]}${n2 ? " " : ""}`);
  return `${modes}`
}

function jsonpath(json) {
  return com.jayway.jsonpath.JsonPath.parse(JSON.stringify(json))
}

function _init(condition, callback) {
  let {
    java
  } = this;
  const separator = "<-separator->"
  let __next_f = [];
  eval(`${this.src.match(/__next_f\.push\(\[1,\s*".+?"\]\)/gi)}`);
  let __next_f_text = __next_f.map(item => item[1]).join("");
  __next_f_text = __next_f_text.replace(/(\n)?\w+:(?:\w{0,3}(\[|\{|"\$)|(null|\w{1,6},))/g, (_, _1, _2, _3) => `${_1 ? separator : ''}${_2 || ''}${_3 || ''}`);
  // java.log(__next_f_text + "\n\n======");
  return __next_f_text.split(separator).reduce((arr, item, index) => {
    item = item.replace(/\\n$/, "");
    try {
      item = item == "null" ? [] : JSON.parse(item);
    } catch (err) {
      item = [];
    }
    try {
      // java.log(`${index}  ${JSON.stringify(item)}\n\n`)
      if (condition && eval(condition)) {
        typeof callback == "function" && callback(item, index, arr);
      }
    } catch (err) {
      // java.log(`${index}  =错误=  ${item}\n${err}\n\n`);
    }
    // java.log(`${index}  ${JSON.stringify(item)} \n\n`)
    return arr
  }, [])
}
/*
手机品牌型号汇总
https://khwang9883.github.io/MobileModels/
安卓谷歌浏览器版本号
https://vikyd.github.io/download-chromium-history-version/json/ver-pos-os/version-position-Android.json
*/
function rMR(from, to) {
  from = parseInt(from);
  to = parseInt(to || 0);
  // 确保`from`小于等于`to`
  [from, to] = [Math.min(from, to), Math.max(from, to)];
  return Math.floor(Math.random() * (to - from + 1)) + from;
}

function randomUA() {
  let { java, cache } = this;
  // 谷歌浏览器版本号
  let chromeVersion;
  // android版本号 10-14
  let androidVersion = rMR(10, 14);
  try {
    let chromeVerList;
    if (cache.get("chromelist")) {
      chromeVerList = JSON.parse(cache.get("chromelist"));
    } else {
      // 获取谷歌浏览器版本号列表
      let chromeResult = java.ajax("https://vikyd.github.io/download-chromium-history-version/json/ver-pos-os/version-position-Android.json");
      chromeVerList = Object.keys(JSON.parse(chromeResult));
      cache.put("chromelist", JSON.stringify(chromeVerList), 86400);
    }
    chromeVersion = chromeVerList[rMR(0, 40)] || `119.0.6045.${rMR(190, 205)}`;
  } catch (error) {
    chromeVersion = `119.0.6045.${rMR(190, 205)}  `;
  }
  return `Mozilla/5.0 (Linux; Android ${androidVersion};) AppleWebKit/537.36 (KHTML, like Gecko) Chrome/${chromeVersion} Mobile Safari/537.36`;
}

